@startuml
skinparam packageStyle rectangle

package "Aggregate-Buch" {
    class Buch as B {
        <<root entity>>
    }

    class AutorID as A {
        <<value>>
    }

    class BuchID as BI {
        <<value>>
    }

    class Kapitel as K {
        <<entity>>
    }

    class KapitelID as KI {
        <<value>>
    }

    class Status as S {
        <<value>>
    }

    ' Relationships
    B --|> A : aggregation
    B --> BI : composition
    B --|> K : aggregation
    K --> KI : composition
    K --> S : composition
    B --> S : composition

    ' Styling to match the diagram
    skinparam classAttributeIconSize 0
    style B fill:#f5f5f5,stroke:#333
    style A fill:#f5f5f5,stroke:#333
    style BI fill:#f5f5f5,stroke:#333
    style K fill:#f5f5f5,stroke:#333
    style KI fill:#f5f5f5,stroke:#333
    style S fill:#f5f5f5,stroke:#333

    ' Add icons for C and E
    note right of B: C
    note right of A: C
    note right of BI: C
    note right of K: C
    note right of KI: C
    note right of S: E

    ' Color the notes
    style note fill:#90EE90,stroke:#2E8B57
    style note fill:#FF6347,stroke:#CD5C5C
}
@enduml
